#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007
#define MAXN 100

// Define the structure for a tree node
typedef struct Node {
    int value;
    struct Node* left;
    struct Node* right;
} Node;

// Function to create a new tree node
Node* createNode(int value) {
    Node* newNode = (Node*) malloc(sizeof(Node));
    newNode->value = value;
    newNode->left = NULL;
    newNode->right = NULL;
    return newNode;
}

// Function to find the least common ancestor of two nodes
Node* findLCA(Node* root, int x, int y) {
    if (root == NULL) return NULL;
    if (root->value == x || root->value == y) return root;
    Node* leftLCA = findLCA(root->left, x, y);
    Node* rightLCA = findLCA(root->right, x, y);
    if (leftLCA && rightLCA) return root;
    return leftLCA ? leftLCA : rightLCA;
}

// Function to update the product of possible roots
void updateProduct(Node* root, int x, int y, int* product) {
    Node* lca = findLCA(root, x, y);
    if (lca->value == x || lca->value == y) {
        *product = (*product * lca->value) % MOD;
    }
}

int main() {
    int N, M;
    scanf("%d %d", &N, &M);
    Node* root = createNode(1);
    // Construct the tree using the given edges
    for (int i = 0; i < N - 1; i++) {
        int x, y;
        scanf("%d %d", &x, &y);
        // Add the edge to the tree
    }
    int product = 1;
    for (int i = 0; i < M; i++) {
        char query;
        int x, y;
        scanf(" %c %d %d", &query, &x, &y);
        if (query == '+') {
            updateProduct(root, x, y, &product);
        } else {
            // Remove the edge from the tree
        }
        printf("%d\n", product);
    }
    return 0;
}

